UPDATE TBL_STOCK
SET STOCK_QTY = STOCK_QTY - #{transferQty},
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{processUser}
WHERE CMPY_CD = #{cmpyCd}
  AND AGNT_CD = #{agntCd}
  AND MTRL_CD = #{mtrlCd}
  AND LOC_ID  = #{fromLocId}
  AND (STOCK_QTY - ISNULL(ALLOCATED_QTY, 0)) >= #{transferQty}

